```typescript
import React, { Component, ReactNode } from 'react';
import { EntryDetailModal, TopSetupsModal, ToastNotification } from './index';

interface ErrorBoundaryProps {
    children: ReactNode;
}

interface ErrorBoundaryState {
    hasError: boolean;
}

class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
    state: ErrorBoundaryState = { hasError: false };

    static getDerivedStateFromError(error: any) {
        return { hasError: true };
    }

    componentDidCatch(error: any, errorInfo: any) {
        console.error("Chart Error:", error, errorInfo);
    }

    render() {
        if (this.state.hasError) return (
            <div className="flex items-center justify-center h-full text-red-500 bg-gray-900 p-4 flex-col gap-4">
                <h3 className="font-bold text-lg">Chart Component Error</h3>
                <p className="text-sm text-gray-400">Something went wrong while rendering the chart.</p>
                <button onClick={() => window.location.reload()} className="bg-blue-600 text-white px-4 py-2 rounded">Reload Page</button>
            </div>
        );
        return this.props.children;
    }
}
```

```tsx
import React, { FC, ReactNode, useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@radix-ui/react-dialog';
import { Button } from '@/components/ui/button';
import { IoIosCloseCircle } from 'react-icons/io';
import { EntryDetailModal, TopSetupsModal, ToastNotification } from './index';
import { ModalProps } from '@/types';
import { ErrorBoundary } from '@/components/error-boundary';

interface Props {
  children?: ReactNode;
  title: string;
  isOpen: boolean;
  onOpenChange: (isOpen: boolean) => void;
  variant?: 'detail' | 'setups';
  entryID?: string;
}

const Modal: FC<Props> = ({ children, title, isOpen, onOpenChange, variant, entryID }) => {
  const [isAlertOpen, setIsAlertOpen] = useState(false);

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent className='bg-primary/50 text-primary-foreground border-border border-2 rounded-2xl'>
        <DialogHeader className='flex flex-row items-center justify-between'>
          <DialogTitle className='text-lg font-bold'>{title}</DialogTitle>
          <Button variant='link' onClick={() => onOpenChange(false)}>
            <IoIosCloseCircle size={28} />
          </Button>
        </DialogHeader>
        <div className='mt-4'>
          {variant === 'detail' && (
            <ErrorBoundary>
              <EntryDetailModal entryId={entryID as string} setIsAlertOpen={setIsAlertOpen} />
            </ErrorBoundary>
          )}
          {variant === 'setups' && (
            <ErrorBoundary>
              <TopSetupsModal entryId={entryID as string} />
            </ErrorBoundary>
          )}
          {children}
        </div>
      </DialogContent>
      <ToastNotification isOpen={isAlertOpen} setIsOpen={setIsAlertOpen} />
    </Dialog>
  );
};

export default Modal;
```


